I cannot directly generate or render a 3D model file (like .obj or .fbx) that you can download. However, I can provide you with the **complete code** to generate a 3D house using **Three.js**, a popular JavaScript library for 3D graphics.

You can run this code immediately in your browser to see a rendered 3D house.

### How to use this:
1.  Create a new file on your computer named `house.html`.
2.  Paste the code below into that file.
3.  Open `house.html` in any modern web browser (Chrome, Firefox, Edge).

### The Code (HTML + JavaScript)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Render (Click & Drag to Rotate)</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        // 2. Camera Setup
        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        // 3. Renderer Setup
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 4. Controls (Orbit)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 5. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 6. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xeeeeee });
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5c3a21 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 7. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with box
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        const windowGeo = new THREE.BoxGeometry(1.5, 1.5, 0.2);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(-1.5, 4, 4.1);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(1.5, 4, 4.1);
        houseGroup.add(win2);

        // Side Window
        const win3 = new THREE.Mesh(windowGeo, windowMaterial);
        win3.position.set(4.1, 4, -1.5);
        houseGroup.add(win3);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.5, 4.1);
        houseGroup.add(door);

        // Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, wallMaterial);
        chimney.position.set(2, 9, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 8. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Sets up the Scene:** Creates a 3D environment with a sky-blue background and fog.
2.  **Lighting:** Adds a directional light (simulating the sun) that casts shadows, and an ambient light to fill in dark areas.
3.  **Geometry Construction:**
    *   **Body:** A cube for the walls.
    *   **Roof:** A cone rotated to look like a pyramid roof.
    *   **Details:** Adds smaller boxes for windows, a door, and a chimney.
4.  **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house, or scroll to zoom in/out.
